import React, { useState } from 'react';

function EvaluationComponent({ phraseId, userId, onEvaluationSubmitted }) {
  const [rating, setRating] = useState(null);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async () => {
    if (rating === null || rating < 0 || rating > 5) {
      setError('Por favor, selecione uma nota entre 0 e 5.');
      return;
    }
    setIsSubmitting(true);
    setError('');
    setMessage('');
    try {
      const response = await fetch('/api/evaluations', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          phraseId,
          userId,
          rating
        })
      });
      const data = await response.json();
      if (response.ok) {
        setMessage('Avaliação armazenada com sucesso.');
        onEvaluationSubmitted && onEvaluationSubmitted(rating);
      } else {
        setError(data.error || 'Erro ao enviar avaliação.');
      }
    } catch (err) {
      setError('Erro de rede ao enviar avaliação.');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (!phraseId) {
    return null;
  }

  return (
    <div aria-live="polite" style={{ marginTop: '1rem' }}>
      <label htmlFor="rating-select">Avalie a frase (0 a 5):</label>
      <select
        id="rating-select"
        value={rating !== null ? rating : ''}
        onChange={e => setRating(Number(e.target.value))}
        aria-required="true"
        disabled={isSubmitting}
      >
        <option value="" disabled>
          Selecione
        </option>
        {[0, 1, 2, 3, 4, 5].map(num => (
          <option key={num} value={num}>
            {num}
          </option>
        ))}
      </select>
      <button onClick={handleSubmit} disabled={isSubmitting || rating === null} style={{ marginLeft: '0.5rem' }}>
        Enviar
      </button>
      {message && <p role="alert" style={{ color: 'green' }}>{message}</p>}
      {error && <p role="alert" style={{ color: 'red' }}>{error}</p>}
    </div>
  );
}

export default EvaluationComponent;

const express = require('express');
const router = express.Router();
const { body, validationResult } = require('express-validator');
const authenticate = require('./middleware/authenticate');
const db = require('./db'); // Assume a module to interact with PostgreSQL

router.post(
  '/evaluations',
  authenticate,
  body('rating').isInt({ min: 0, max: 5 }),
  body('phraseId').isString().notEmpty(),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Nota inválida ou dados ausentes.' });
    }

    const { rating, phraseId } = req.body;
    const userId = req.user.id;

    try {
      // Store encrypted rating in PostgreSQL
      // Assuming db.query uses parameterized queries and encryption handled at DB or app layer
      await db.query(
        'INSERT INTO evaluations (phrase_id, user_id, rating_encrypted) VALUES ($1, $2, pgp_sym_encrypt($3::text, current_setting(''app.encryption_key'')))',
        [phraseId, userId, rating.toString()]
      );

      res.json({ message: 'Avaliação armazenada com sucesso.' });
    } catch (err) {
      console.error('Erro ao armazenar avaliação:', err);
      res.status(500).json({ error: 'Erro interno do servidor.' });
    }
  }
);

module.exports = router;
